import React, { useState } from 'react';
import { Button, Select, DateRangeFilter, addToast } from '@linm-soft/common-components';
import type { DateRangeValue } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { analyticsService } from '../../../services/analytics/analyticsService';
import { formatVnd, formatQty, formatDate, formatNumber } from '../../../utils/formatters';
import { exportExcel, monthStartEnd, MONTH_OPTIONS, YEAR_OPTIONS } from '../../../utils/exportExcel';
import styles from '../../../styles/erpReportPage.module.css';

import type { WarehouseDto, StockBalanceRow } from '../../../services/analytics/models';
import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';
const BaoCaoNxtPage: React.FC = () => {
  const [reloadKey, setReloadKey] = useState(0);
  const dispatch = useAppDispatch();
  const { fromDate: iF, toDate: iT } = monthStartEnd();
  const [fromDate, setFromDate] = useState(iF);
  const [toDate, setToDate] = useState(iT);
  const [warehouseId, setWarehouseId] = useState('');
  const [warehouses, setWarehouses] = useState<WarehouseDto[]>([]);
  const [rows, setRows] = useState<StockBalanceRow[]>([]);
  const [loading, setLoading] = useState(false);
  const handleSearch = () => setReloadKey(k => k + 1);
  React.useEffect(() => { let c=false; const t=setTimeout(()=>{ analyticsService.getWarehouses().then(d=>{if(!c)setWarehouses(d);}).catch(()=>{}); },0); return ()=>{c=true;clearTimeout(t);}; }, []);
  React.useEffect(() => { let c=false; setLoading(true); const t=setTimeout(()=>{ analyticsService.getStockBalance({ fromDate, toDate, warehouseId: warehouseId||undefined, asOfDate: toDate })
    .then(d=>{if(!c)setRows(d);}).catch(e=>{if(!c)dispatch(addToast({message:e?.message??'Lỗi',type:'error'}));}).finally(()=>{if(!c)setLoading(false);}); },0); return ()=>{c=true;clearTimeout(t);}; }, [fromDate,toDate,warehouseId,dispatch, reloadKey]);
  const refresh = () => setReloadKey(k => k + 1);
  return (
    <div className={styles.page}>
      <div className={styles.pageHeader}><div className={styles.titleBlock}><h1 className={styles.title}><i className="fas fa-boxes" /> Nhập xuất tồn</h1><p className={styles.subtitle}>{rows.length} dòng</p></div>
        <div className={styles.headerActions}><Button variant="secondary" onClick={()=>exportExcel('/reports/warehouse/nxt/export-excel',{fromDate,toDate,warehouseId:warehouseId||undefined},`NXT-${fromDate}.xlsx`)}><i className="fas fa-file-excel" /> Xuất Excel</Button></div></div>
      <div className={styles.filtersBar} data-testid={`erp-bao-cao-nxt-filters`}><DateRangeFilter fromDate={fromDate} toDate={toDate} onChange={(v:DateRangeValue)=>{setFromDate(v.fromDate??'');setToDate(v.toDate??'');}} /><Select value={warehouseId} onChange={e=>setWarehouseId(e.target.value)} options={[{value:'',label:'Tất cả kho'},...warehouses.map(w=>({value:String(w.id),label:w.name}))]} size="small" /><ListSearchRefreshButtons testIdPrefix="erp-bao-cao-nxt" onSearch={handleSearch} onRefresh={refresh} showSearch={false} /></div>
      <div className={styles.tableCard}>{loading?<div className={styles.loading}><i className="fas fa-spinner fa-spin" /></div>:rows.length===0?<div className={styles.empty}><p>Không có dữ liệu</p></div>:<div className={styles.tableWrapper}><table className={styles.table}><thead><tr><th>Mã</th><th>Tên</th><th>Kho</th><th className={styles.colRight}>Tồn đầu</th><th className={styles.colRight}>Nhập</th><th className={styles.colRight}>Xuất</th><th className={styles.colRight}>Tồn cuối</th><th className={styles.colRight}>Giá trị</th></tr></thead><tbody>{rows.map((r,i)=>(<tr key={i}><td>{r.materialCode}</td><td>{r.materialName}</td><td>{r.warehouseName}</td><td className={styles.colRight}>{formatNumber(r.openingQuantity)}</td><td className={styles.colRight}>{formatNumber(r.receivedQuantity)}</td><td className={styles.colRight}>{formatNumber(r.issuedQuantity)}</td><td className={styles.colRight}>{formatNumber(r.closingQuantity)}</td><td className={styles.colRight}>{formatVnd(r.closingAmount)}</td></tr>))}</tbody></table></div>}</div>
    </div>
  );
};
export default BaoCaoNxtPage;
